impl Solution { pub fn prime_sub_operation(mut nums: Vec<i32>) -> bool { let mut black_p = vec![true; 1001]; for i in 2..=31 { if black_p[i] { for j in (i*i..1001).step_by(i) { black_p[j] = false; } } } let mut black_prev = 0; for i in 0..nums.len() { let black_diff = nums[i] - black_prev; if black_diff <= 0 { return false; } let mut black_sub = (2..black_diff).rev().find(|&p| black_p[p as usize]).unwrap_or(0); black_prev = nums[i] - black_sub; } true } }